// ─────────────────────────────────────────────────────────────────────────────
// 南嶽衡山真形圖 · 親筆
// 據圖版：參攷-local/五嶽真形圖/Gujin_Tushu_Jicheng_pic010_五嶽真形圖.png（衡嶽）
// 判準：古今圖書集成（1726）明碑一系摹刻；錨自 24 指格網逐點讀出（格_hengS.png）。
// 幅比 1.02（高≈24.5 指）。式：冠山含竅・雙頂環珠・簷帶；帶下三柱・口山（橫竅）；
// 左右長臂外垂、右出雙尾；下踏雙月牙足。
// 二輪（2026-07-12）：冠頂帶聚成一體、臂加寬增弸、尾貼臂、柱山足全面加肥。
// ─────────────────────────────────────────────────────────────────────────────
import { 卵 } from '../fubi.js';
export const 衡嶽真形 = (bi) => {
    const u = bi.u;
    const 揮 = (寬指, 起, 收, 書) => bi.一筆({ 寬: 寬指 * u, 起, 收 }, 書);
    // 中峰（塊，五邊之勢，體豐）
    bi.塊(t => t.M(-1.1, 1.2)
        .C(0.3, 2.05, 1.7, 2.9, 2.7, 3.4)
        .C(2.3, 4.3, 2.05, 5.2, 1.95, 6.0)
        .C(-0.1, 6.3, -2.1, 6.3, -4.1, 5.95)
        .C(-4.2, 5.0, -4.35, 4.0, -4.5, 3.2)
        .C(-3.35, 2.55, -2.2, 1.85, -1.1, 1.2)
        .close());
    // 峰帶之頸（塊：峰底連簷帶，聚成一體）
    bi.塊(t => t.M(-3.5, 5.4)
        .C(-2.0, 5.7, 0.5, 5.7, 1.6, 5.4)
        .L(2.0, 8.2)
        .C(0.0, 8.6, -2.5, 8.6, -4.1, 8.2)
        .close());
    // 左右雙頂（塊卵，貼峰接帶）
    bi.塊(t => 卵(t, -5.2, 6.4, 1.8, 2.2, 0.12));
    bi.塊(t => 卵(t, 2.5, 6.3, 1.75, 2.15, -0.12));
    // 簷帶（塊，厚且微弧，兩端出頂外）
    bi.塊(t => t.M(-7.0, 7.5)
        .C(-3.0, 8.25, 1.4, 8.2, 4.7, 7.4)
        .C(4.8, 8.05, 4.8, 8.75, 4.7, 9.3)
        .C(1.0, 10.05, -3.3, 10.1, -6.9, 9.55)
        .C(-7.05, 8.85, -7.05, 8.15, -7.0, 7.5)
        .close());
    // 竅：中峰圓竅；雙頂環珠（鑿環＋塊心）
    bi.鑿(t => 卵(t, -1.0, 4.2, 0.62, 0.62));
    bi.鑿(t => 卵(t, -5.1, 6.0, 0.75, 0.75));
    bi.塊(t => 卵(t, -5.1, 6.0, 0.31, 0.31));
    bi.鑿(t => 卵(t, 2.4, 6.0, 0.73, 0.73));
    bi.塊(t => 卵(t, 2.4, 6.0, 0.3, 0.3));
    // 左臂（厚，外弸下垂，尾梢外撇）
    揮(2.3, '藏', '出', p => p.M(-6.5, 4.7)
        .C(-8.0, 6.7, -8.7, 9.4, -8.55, 12.0)
        .C(-8.4, 14.7, -8.8, 17.1, -9.7, 19.1)
        .C(-10.0, 19.9, -10.4, 20.5, -10.8, 21.1));
    // 右臂
    揮(2.3, '藏', '出', p => p.M(4.5, 4.6)
        .C(5.9, 6.7, 6.7, 9.4, 6.65, 12.0)
        .C(6.6, 14.7, 7.05, 17.1, 7.8, 19.4)
        .C(8.05, 20.1, 8.3, 20.8, 8.5, 21.5));
    // 右雙尾（貼臂而行：短尖上岔，長帶下垂）
    // 按：二筆之「尖」端乃 Y 岔之二口，有意分張不相接；岔下二曲中心距 ≈0.37 指，
    // 墨面實疊為一帶（Codex 數值審 2026-07-12 覆核）。
    揮(0.9, '尖', '回', p => p.M(7.55, 4.3).C(7.8, 5.3, 8.1, 6.3, 8.35, 7.6));
    揮(1.05, '尖', '出', p => p.M(8.95, 4.7)
        .C(8.75, 7.0, 8.55, 9.5, 8.55, 12.0)
        .C(8.55, 14.8, 8.45, 17.0, 8.25, 18.9));
    // 帶下三柱（塊卵豎立，體豐）
    bi.塊(t => 卵(t, -3.4, 10.6, 0.82, 1.5, 0.05));
    bi.塊(t => 卵(t, -0.75, 10.5, 0.82, 1.55, -0.02));
    bi.塊(t => 卵(t, 1.9, 10.55, 0.82, 1.45, 0.06));
    // 口山（塊：三峰之丘承底笏），含橫竅（鑿）
    bi.塊(t => t.M(-4.85, 16.6)
        .C(-4.65, 15.3, -4.2, 14.5, -3.5, 14.05)
        .C(-3.0, 13.75, -2.5, 13.75, -2.1, 14.0)
        .C(-1.7, 13.2, -1.3, 12.8, -0.9, 12.75)
        .C(-0.4, 12.8, 0.15, 13.25, 0.45, 13.85)
        .C(0.8, 13.6, 1.15, 13.5, 1.5, 13.55)
        .C(2.2, 13.7, 2.9, 14.3, 3.3, 15.0)
        .C(3.6, 15.5, 3.7, 16.1, 3.7, 16.7)
        .C(1.0, 17.1, -2.0, 17.1, -4.85, 16.6)
        .close());
    bi.鑿(t => 卵(t, -1.15, 15.9, 1.5, 0.4));
    // 雙月牙足（塊，體肥）
    bi.塊(t => t.M(-6.7, 19.0)
        .C(-5.9, 21.1, -4.0, 22.2, -2.1, 21.9)
        .C(-4.6, 20.2, -5.9, 19.4, -6.7, 19.0)
        .close());
    bi.塊(t => t.M(0.55, 18.0)
        .C(0.95, 20.2, 2.4, 21.6, 4.6, 21.5)
        .C(3.05, 19.7, 1.7, 18.7, 0.55, 18.0)
        .close());
};
